#pragma once
#include <JuceHeader.h>
#include "Theme.h"
class RomanticLookAndFeel final: public juce::LookAndFeel_V4 { public: RomanticLookAndFeel(){setColour(juce::Slider::textBoxTextColourId,RomanticTheme::text);setColour(juce::Slider::textBoxBackgroundColourId,juce::Colours::transparentBlack);setColour(juce::Slider::textBoxOutlineColourId,juce::Colours::transparentBlack);} void drawRotarySlider(juce::Graphics& g,int x,int y,int w,int h,float pos,float a0,float a1,juce::Slider&) override {auto b=juce::Rectangle<float>((float)x,(float)y,(float)w,(float)h).reduced(8);auto c=b.getCentre();g.setColour(juce::Colours::black.withAlpha(.55f));g.fillEllipse(b.translated(0,4));juce::ColourGradient gr(juce::Colour::fromRGB(91,76,73),c.x,b.getY(),juce::Colour::fromRGB(27,23,25),c.x,b.getBottom(),false);g.setGradientFill(gr);g.fillEllipse(b);g.setColour(RomanticTheme::border);g.drawEllipse(b,1.5f);juce::Path p;p.addCentredArc(c.x,c.y,b.getWidth()*.5f-4,b.getHeight()*.5f-4,0,a0,a0+pos*(a1-a0),true);g.setColour(RomanticTheme::accentBright);g.strokePath(p,juce::PathStrokeType(3));} };
